from flask import Flask, render_template, redirect, url_for, request
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

data_path = 'data'

# --- Utility functions for data loading and saving ---

def read_file_lines(filename):
    try:
        with open(os.path.join(data_path, filename), 'r', encoding='utf-8') as f:
            lines = f.readlines()
        return [line.strip() for line in lines if line.strip()]
    except FileNotFoundError:
        return []

def write_file_lines(filename, lines):
    with open(os.path.join(data_path, filename), 'w', encoding='utf-8') as f:
        for line in lines:
            f.write(line + '\n')

# --- Data schema handlers ---

# Pets: id|name|type|age|description|available
# id: str
# name: str
# type: str
# age: str
# description: str
# available: 'True'/'False'

def load_pets():
    pets = []
    lines = read_file_lines('pets.txt')
    for line in lines:
        fields = line.split('|')
        if len(fields) != 6:
            continue
        pet = {
            'id': fields[0],
            'name': fields[1],
            'type': fields[2],
            'age': fields[3],
            'description': fields[4],
            'available': fields[5] == 'True'
        }
        pets.append(pet)
    return pets


def save_pets(pets):
    lines = []
    for pet in pets:
        available_val = 'True' if pet.get('available', False) else 'False'
        line = '|'.join([
            pet.get('id',''),
            pet.get('name',''),
            pet.get('type',''),
            pet.get('age',''),
            pet.get('description',''),
            available_val
        ])
        lines.append(line)
    write_file_lines('pets.txt', lines)

# Users: id|username|email|password|favorites|adopted_pets
# favorites and adopted_pets stored as comma separated pet ids

def load_users():
    users = []
    lines = read_file_lines('users.txt')
    for line in lines:
        fields = line.split('|')
        if len(fields) != 6:
            continue
        user = {
            'id': fields[0],
            'username': fields[1],
            'email': fields[2],
            'password': fields[3],
            'favorites': fields[4].split(',') if fields[4] else [],
            'adopted_pets': fields[5].split(',') if fields[5] else []
        }
        users.append(user)
    return users


def save_users(users):
    lines = []
    for user in users:
        favs = ','.join(user.get('favorites', [])) if user.get('favorites') else ''
        adopted = ','.join(user.get('adopted_pets', [])) if user.get('adopted_pets') else ''
        line = '|'.join([
            user.get('id',''),
            user.get('username',''),
            user.get('email',''),
            user.get('password',''),
            favs,
            adopted
        ])
        lines.append(line)
    write_file_lines('users.txt', lines)

